import React, {  useEffect, useState } from "react";
import {useLocation, useNavigate} from "react-router-dom";
import './Logout.css';
// import './Welcome';
import axios from "axios";
// import { FaCheck } from "react-icons/fa";
// import { FaPlus } from "react-icons/fa";
// import { FaTimes } from "react-icons/fa";
function Logout () {
    const [responses, setResponse] = useState([]);
    const [deleteResponse, setDeleteResponse] = useState([]);

    // useEffect((userName) => {
    //     axios.get(`http://localhost:8080/user/${userName}/items`).then(response => setResponse(response.data))
    //     .catch(error => {console.log("An error happened:" + error)})
    // }, []);

    useEffect(() => {
        getData()
    }, []);

    const getData = (userName) => {
         axios.get(`http://localhost:8080/user/${userName}/items`).then(response => console.log(response))
        .catch(error => {console.log("An error happened:" + error)})
    }
    const navigate = useNavigate();
    const location = useLocation();
//     useEffect((userName, id) => {
//         axios.delete(`http://localhost:8080/users/${userName}/items/${id}`).then(response => setDeleteResponse(response.userName, response.id))
//        .catch(error => {console.log("An error happened:" + error)})
//    }, []);
   const deleteRequest = (userName, id) => {
        axios.delete(`http://localhost:8080/users/${userName}/items/${id}`).then(response => setDeleteResponse(response.userName,response.id))
       .catch(error => {console.log(error.data)})
        getData();
   }
    return (
        <div>
        <link rel="stylesheet" href="https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.3.0/css/all.min.css"/>
        <div>
        <div className="header">
        <a href="/" onClick={() => navigate('/')}className="logo">Productiv</a>
        <div className="header-right">
       {/* Create loader! */}
        <a href="Welcome" onClick={() => navigate('Welcome')}>My Account</a>
        <a href="/" onClick={() => navigate('/')}>Logout</a>
        </div>
        </div>
        <h1>Welcome!</h1>
            {/* <h1>Welcome {location.state.userName}!</h1> */}
        </div>
            <table className="list-of-itmes">
                <tr>
                    <th>Number</th>
                    <th>Description</th>
                    <th>Date</th>
                    <th>Status</th>
                    <th>Add</th>
                    <th>Delete</th>
                    <th>Update</th>
                </tr>
                {
                 responses.map(response => (
                 <tr>
                 <td>{response.id}</td>
                 <td>{response.description}</td>
                 <td>{response.targetDate}</td>
                 <td>{response.isDone}</td>
                 <td><button className="add-button" onClick={() => navigate('Add')}>Add</button></td>
                 <td><button className="delete-button" onClick={() => deleteRequest(response.userName, response.id)}>Delete</button></td>
                 <td><button className="update-button" onClick={() => navigate('Update')}>Update</button></td>
                 </tr>
                 ))
                }
            </table>
        </div>
    )
}

export default Logout;
